/**
 * JSZip - Standard Production Version for Amazon Extension
 * Clean ASCII-safe implementation to prevent corruption.
 */
(function(window) {
    "use strict";

    function JSZip() {
        if (!(this instanceof JSZip)) return new JSZip();
        this.files = {};
        this.root = "";
    }

    JSZip.prototype.file = function(name, data, options) {
        const fullPath = this.root + name;
        this.files[fullPath] = {
            name: fullPath,
            data: data,
            options: options || {},
            dir: false
        };
        return this;
    };

    JSZip.prototype.folder = function(name) {
        if (name && name.slice(-1) !== "/") name += "/";
        const fullPath = this.root + (name || "");
        if (!this.files[fullPath]) {
            this.files[fullPath] = { name: fullPath, dir: true };
        }
        const child = new JSZip();
        child.files = this.files;
        child.root = fullPath;
        return child;
    };

    // Fast CRC32 table
    const crcTable = new Uint32Array(256);
    for (let i = 0; i < 256; i++) {
        let c = i;
        for (let k = 0; k < 8; k++) {
            c = (c & 1) ? (0xEDB88320 ^ (c >>> 1)) : (c >>> 1);
        }
        crcTable[i] = c;
    }

    function crc32(data) {
        let crc = 0xffffffff;
        const b = (data instanceof Uint8Array) ? data : new TextEncoder().encode(data);
        for (let i = 0; i < b.length; i++) {
            crc = (crc >>> 8) ^ crcTable[(crc ^ b[i]) & 0xff];
        }
        return (crc ^ 0xffffffff) >>> 0;
    }

    JSZip.prototype.generateAsync = function() {
        const self = this;
        return new Promise((resolve) => {
            const parts = [];
            const central = [];
            const names = Object.keys(self.files).sort();
            let offset = 0;
            const now = new Date();
            const time = (now.getHours() << 11) | (now.getMinutes() << 5) | (now.getSeconds() >> 1);
            const date = ((now.getFullYear() - 1980) << 9) | ((now.getMonth() + 1) << 5) | now.getDate();

            names.forEach(name => {
                const f = self.files[name];
                const isDir = !!f.dir;
                let data = f.data || "";
                if (!(data instanceof Uint8Array)) data = new TextEncoder().encode(data);
                if (isDir) data = new Uint8Array(0);

                const nameBuf = new TextEncoder().encode(name);
                const crc = isDir ? 0 : crc32(data);

                // Local Header
                const lHeader = new Uint8Array(30 + nameBuf.length);
                lHeader.set([0x50, 0x4B, 0x03, 0x04, 0x14, 0x00, 0x00, 0x00, 0x00, 0x00, time & 0xFF, time >> 8, date & 0xFF, date >> 8]);
                lHeader.set([crc & 0xFF, (crc >> 8) & 0xFF, (crc >> 16) & 0xFF, (crc >> 24) & 0xFF], 14);
                lHeader.set([data.length & 0xFF, (data.length >> 8) & 0xFF, (data.length >> 16) & 0xFF, (data.length >> 24) & 0xFF], 18);
                lHeader.set([data.length & 0xFF, (data.length >> 8) & 0xFF, (data.length >> 16) & 0xFF, (data.length >> 24) & 0xFF], 22);
                lHeader.set([nameBuf.length & 0xFF, nameBuf.length >> 8, 0, 0], 26);
                lHeader.set(nameBuf, 30);
                
                parts.push(lHeader);
                if (!isDir) parts.push(data);

                // Central Directory Header
                const cHeader = new Uint8Array(46 + nameBuf.length);
                cHeader.set([0x50, 0x4B, 0x01, 0x02, 0x14, 0x00, 0x14, 0x00, 0x00, 0x00, 0x00, 0x00, time & 0xFF, time >> 8, date & 0xFF, date >> 8]);
                cHeader.set([crc & 0xFF, (crc >> 8) & 0xFF, (crc >> 16) & 0xFF, (crc >> 24) & 0xFF], 16);
                cHeader.set([data.length & 0xFF, (data.length >> 8) & 0xFF, (data.length >> 16) & 0xFF, (data.length >> 24) & 0xFF], 20);
                cHeader.set([data.length & 0xFF, (data.length >> 8) & 0xFF, (data.length >> 16) & 0xFF, (data.length >> 24) & 0xFF], 24);
                cHeader.set([nameBuf.length & 0xFF, nameBuf.length >> 8, 0, 0, 0, 0, 0, 0, 0, 0, isDir ? 0x10 : 0x00, 0x00, 0x00, 0x00], 28);
                cHeader.set([offset & 0xFF, (offset >> 8) & 0xFF, (offset >> 16) & 0xFF, (offset >> 24) & 0xFF], 42);
                cHeader.set(nameBuf, 46);
                central.push(cHeader);

                offset += lHeader.length + data.length;
            });

            const cSize = central.reduce((a, b) => a + b.length, 0);
            const eocd = new Uint8Array(22);
            eocd.set([0x50, 0x4B, 0x05, 0x06, 0, 0, 0, 0, names.length & 0xFF, names.length >> 8, names.length & 0xFF, names.length >> 8, 
                      cSize & 0xFF, (cSize >> 8) & 0xFF, (cSize >> 16) & 0xFF, (cSize >> 24) & 0xFF, 
                      offset & 0xFF, (offset >> 8) & 0xFF, (offset >> 16) & 0xFF, (offset >> 24) & 0xFF, 0, 0]);

            const finalSize = offset + cSize + 22;
            const final = new Uint8Array(finalSize);
            let curr = 0;
            parts.forEach(p => { final.set(p, curr); curr += p.length; });
            central.forEach(c => { final.set(c, curr); curr += c.length; });
            final.set(eocd, curr);

            resolve(new Blob([final], { type: "application/zip" }));
        });
    };

    window.JSZip = JSZip;
})(window);
